import React from "react";
import coin from '../img/main-icon.png'
class Welcome extends React.Component{

    render(){
        return(
            <main className="main">
                <section className="welcome">
                    <div className="container">
                    <img className="welcome-img" src={coin} />
                    </div>
                </section>
            </main>
        )
    }
}

export default Welcome
